import{_ as t,o,c as i,a2 as d}from"./chunks/framework.ByXR59UU.js";const f=JSON.parse('{"title":"Detection Overview","description":"","frontmatter":{},"headers":[],"relativePath":"openshield-xdp/detection-engine/overview.md","filePath":"openshield-xdp/detection-engine/overview.md","lastUpdated":null}'),a={name:"openshield-xdp/detection-engine/overview.md"};function r(n,e,s,c,l,p){return o(),i("div",null,[...e[0]||(e[0]=[d('<h1 id="detection-overview" tabindex="-1">Detection Overview <a class="header-anchor" href="#detection-overview" aria-label="Permalink to &quot;Detection Overview&quot;">​</a></h1><p>OpenShield classifies packets at L2–L7 before the kernel processes them. The detection pipeline runs inside the XDP program — zero context switches, zero allocations.</p><h2 id="detection-categories" tabindex="-1">Detection categories <a class="header-anchor" href="#detection-categories" aria-label="Permalink to &quot;Detection categories&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Category</th><th>Vectors</th><th>Checks</th></tr></thead><tbody><tr><td>L2/L3/L4 validation</td><td>12</td><td>MAC filter, IP bogon, bogus TCP flags, malformed headers</td></tr><tr><td>Rate-based scoring</td><td>6</td><td>PPS, BPS, TCP, UDP, ICMP, SYN — per-IP, per-second</td></tr><tr><td>Connection tracking</td><td>2</td><td>Blind SYN-ACK, blind RST</td></tr><tr><td>Amplification</td><td>9</td><td>DNS + 8-port generic UDP reflection</td></tr><tr><td>L7 signature</td><td>16</td><td>Configurable port+protocol+mask rules</td></tr><tr><td>Statistical</td><td>5</td><td>SYN/FIN ratio, entropy, TTL, packet size, connection rate</td></tr><tr><td>SYNPROXY</td><td>1</td><td>Cookie-based SYN flood mitigation</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">All features toggleable</p><p>Each detection vector has a corresponding <code>enabled</code> flag in the config. Disable any that produce false positives for your traffic profile.</p></div><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><p><a href="/pingless-studios-docs/openshield-xdp/detection-engine/pipeline">Pipeline</a> · <a href="/pingless-studios-docs/openshield-xdp/detection-engine/l3-l4">L2/L3/L4 Detection</a></p>',7)])])}const g=t(a,[["render",r]]);export{f as __pageData,g as default};
